  "inlineSchema": "// MoneyLoop — Digital Susu Management System\n// Prisma schema for PostgreSQL (Neon)\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────\n// Enums\n// ─────────────────────────────────────────\n\nenum Role {\n  MEMBER\n  ADMIN\n}\n\nenum Frequency {\n  DAILY\n  WEEKLY\n  MONTHLY\n}\n\nenum GroupStatus {\n  ACTIVE\n  PAUSED\n  COMPLETED\n}\n\nenum GroupMemberRole {\n  TREASURER\n  MEMBER\n}\n\nenum CycleStatus {\n  PENDING // Contributions being collected\n  READY // All contributions in, awaiting payout\n  PAID // Payout sent successfully\n  FAILED // Payout attempt failed\n}\n\nenum ContributionStatus {\n  PENDING\n  SUCCESS\n  FAILED\n}\n\nenum PayoutStatus {\n  PENDING\n  SUCCESS\n  FAILED\n}\n\nenum PayoutAccountStatus {\n  UNSET\n  PENDING_VERIFICATION\n  VERIFIED\n}\n\n// ─────────────────────────────────────────\n// Models\n// ─────────────────────────────────────────\n\nmodel User {\n  id                             String              @id @default(uuid())\n  name                           String\n  email                          String              @unique\n  phone                          String\n  momoNumber                     String? // Active MoMo number for receiving payouts\n  momoNetwork                    String? // MTN | VodafoneCash | AirtelTigo\n  paystackRecipientCode          String? // Cached Paystack transfer recipient code — avoids re-creating on every payout\n  payoutAccountStatus            PayoutAccountStatus @default(UNSET)\n  payoutAccountVerifiedAt        DateTime?\n  payoutAccountLastUpdatedAt     DateTime?\n  payoutAccountChangeLockedUntil DateTime?\n  payoutAccountVerificationError String?\n  pendingMomoNumber              String?\n  pendingMomoNetwork             String?\n  role                           Role                @default(MEMBER)\n  password                       String // hashed with bcrypt\n  createdAt                      DateTime            @default(now())\n  updatedAt                      DateTime            @updatedAt\n\n  // Relations\n  groupMemberships GroupMember[]\n  contributions    Contribution[]\n  payoutsReceived  Payout[]\n  treasurerOf      SusuGroup[]    @relation(\"TreasurerGroups\")\n\n  @@map(\"users\")\n}\n\nmodel SusuGroup {\n  id                 String      @id @default(uuid())\n  name               String\n  contributionAmount Decimal     @db.Decimal(10, 2)\n  frequency          Frequency\n  treasurerId        String\n  currentCycle       Int         @default(1)\n  status             GroupStatus @default(ACTIVE)\n  createdAt          DateTime    @default(now())\n  updatedAt          DateTime    @updatedAt\n\n  // Relations\n  members     GroupMember[]\n  cycles      Cycle[]\n  treasurer   User          @relation(\"TreasurerGroups\", fields: [treasurerId], references: [id])\n  invitations Invitation[]\n\n  @@map(\"susu_groups\")\n}\n\nmodel GroupMember {\n  id             String          @id @default(uuid())\n  userId         String\n  groupId        String\n  payoutPosition Int? // 1-based position in rotation\n  memberRole     GroupMemberRole @default(MEMBER)\n  joinedAt       DateTime        @default(now())\n\n  // Relations\n  user  User      @relation(fields: [userId], references: [id])\n  group SusuGroup @relation(fields: [groupId], references: [id])\n\n  @@unique([groupId, payoutPosition]) // no two members at same position\n  @@unique([groupId, userId]) // one membership per group\n  @@map(\"group_members\")\n}\n\nmodel Cycle {\n  id             String      @id @default(uuid())\n  groupId        String\n  cycleNumber    Int // Which cycle this is within the current round (1, 2, 3...)\n  recipientId    String // The member who receives the payout this cycle\n  payoutDate     DateTime    @db.Date\n  status         CycleStatus @default(PENDING)\n  totalCollected Decimal     @default(0) @db.Decimal(10, 2)\n  createdAt      DateTime    @default(now())\n  updatedAt      DateTime    @updatedAt\n\n  // Relations\n  group         SusuGroup      @relation(fields: [groupId], references: [id])\n  contributions Contribution[]\n  payout        Payout?\n\n  @@unique([groupId, cycleNumber])\n  @@map(\"cycles\")\n}\n\nmodel Contribution {\n  id          String             @id @default(uuid())\n  userId      String\n  cycleId     String\n  amount      Decimal            @db.Decimal(10, 2)\n  paystackRef String?            @unique // Paystack payment reference\n  status      ContributionStatus @default(PENDING)\n  paidAt      DateTime?\n  createdAt   DateTime           @default(now())\n\n  // Relations\n  user  User  @relation(fields: [userId], references: [id])\n  cycle Cycle @relation(fields: [cycleId], references: [id])\n\n  @@unique([userId, cycleId]) // one contribution per member per cycle\n  @@map(\"contributions\")\n}\n\nmodel Payout {\n  id                  String       @id @default(uuid())\n  cycleId             String       @unique\n  recipientId         String\n  amount              Decimal      @db.Decimal(10, 2)\n  paystackTransferId  String? // Paystack transfer ID\n  paystackRecipientId String? // Paystack transfer recipient code\n  status              PayoutStatus @default(PENDING)\n  failureReason       String?\n  sentAt              DateTime?\n  createdAt           DateTime     @default(now())\n  updatedAt           DateTime     @updatedAt\n\n  // Relations\n  cycle     Cycle @relation(fields: [cycleId], references: [id])\n  recipient User  @relation(fields: [recipientId], references: [id])\n\n  @@map(\"payouts\")\n}\n\nmodel Invitation {\n  id        String    @id @default(uuid())\n  groupId   String\n  email     String?\n  token     String    @unique @default(cuid())\n  expiresAt DateTime\n  usedAt    DateTime?\n  createdAt DateTime  @default(now())\n\n  group SusuGroup @relation(fields: [groupId], references: [id])\n\n  @@map(\"invitations\")\n}\n",
